VALUES
  ('judicial-57112235-moex-00767', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依受刑人與被告吸菸管理及戒菸獎勵辦法第13條之規定，對收容人不吸菸及戒菸紀錄每3個月考評 1次，監獄得給獎勵，下列何者非獎勵之項目？', '["增給當月成績總分1分", "增加接見或通信1次至3次", "給與獎勵金", "不吸菸及戒菸之紀錄滿1年者，發給獎狀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00768', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及其施行細則關於受刑人衛生及醫療之規定，下列敘述何者錯誤？', '["監獄應注意環境衛生，每年至少1次舉行環境衛生檢查", "受刑人應配合監獄執行環境清潔工作，維持公共及個人衛生", "監獄依其規模及收容對象、特性，得在資源可及範圍內備置相關醫事人員，於夜間及假日為戒護外 醫之諮詢判斷", "受刑人或其最近親屬及家屬，在不妨礙監獄秩序及經醫師評估有必要之情形下，得請求監獄准許自 費延請醫事人員於監獄內實施健康檢查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00769', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法規定，被許可接見者得攜帶兒童，不計入人數限制，有關兒童年齡之限制，下列敘述何者 正確？', '["僅限攜帶未滿9歲之兒童", "僅限攜帶未滿6歲之兒童", "得攜帶未滿14歲之兒童", "得攜帶未滿12歲之兒童"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00770', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '民國99年5月監獄行刑法第十二次修正公布，下列敘述何者正確？', '["酌作文字修正，將「殘廢」用語修正為「殘障人士」", "增列受刑人有刑法第81條之1規定，受強制治療處分者不得外出之規定", "酌作文字修正，將「殘廢」用語修正為「身心障礙」", "增列受刑人有刑法第91條之1規定，受強制治療處分者得外出之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00771', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人違規之懲罰，下列敘述何者錯誤？', '["受刑人違規情節輕微或顯堪憫恕者，得免其懲罰之執行或緩予執行", "受刑人罹患疾病或有其他特別事由者，得停止執行", "受刑人若免予執行或緩予執行後，如受懲罰者已保持2星期以上之改悔情狀，得廢止其懲罰", "受刑人罹患疾病或有其他特別事由停止執行者，於停止原因消滅後繼續執行。但停止執行逾6個月 不再執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00772', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '除法律另有規定外，監獄人員得閱讀受刑人寄發及收受之書信情形，下列敘述何者錯誤？', '["受刑人於戒護住院期間", "有事實而合理懷疑有意圖加害或騷擾他人之虞", "矯正機關收容人間互通之書信", "受刑人於受懲罰期間內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00773', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人有妨害監獄秩序或安全之行為，監獄得施以懲罰，有關監獄辦理受刑人違規之方式或程序，下 列敘述何者錯誤？', '["數行為構成同一或不同之違規行為而應受懲罰者，從一重懲罰之", "違規事件調查程序中，應作成訪談紀錄，並錄音，必要時，亦得錄影", "受刑人於受懲罰前陳述意見之方式，不限以書面為之", "違規行為不包括受刑人自傷或自殺之行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00774', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關外界對受刑人送入金錢與飲食及必需物品之規定，下列敘述何者錯誤？', '["外界送入金錢，每一送入人對個別收容人每日限1次，每次以新臺幣1萬元為限。但經機關長官許 可者，不在此限", "外界送入飲食，受刑人每3日1次，每次不得逾2公斤。但經機關長官許可者，不在此限", "外界送入飲食之種類，以水果、飲料、糕點及餅乾為限", "外界送入必需物品，每一送入人對個別收容人每月限1次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00775', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人之陳情、申訴及起訴之規定，下列敘述何者錯誤？', '["受刑人得以書面或言詞向監獄、視察小組或其他視察人員提出陳情", "受刑人或代理人經監獄或法院之許可，得偕同輔佐人到場", "受刑人因監獄對其依監獄行刑法請求之事件，於2個月內不依其請求作成決定，認為權益受損害， 不依請求作成決定之申訴，應自受刑人提出請求屆滿1個月之次日起，20日不變期間內為之", "監獄認為受刑人之申訴有理由者，應逕為立即停止、撤銷或變更原處分、管理措施之決定或執行， 或依其請求或申訴作成決定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00776', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第102條規定，監獄應設申訴審議小組處理相關申訴事件，審議小組進行審議時，下列 敘述何者錯誤？', '["應通知申訴人、委任代理人及輔佐人列席陳述意見", "委任代理人及輔佐人無法出席者，其陳述意見應以書面、影音、視訊、電話或其他方式為之", "陳述人以書面以外方式陳述意見者，監獄應作成紀錄", "陳述人對紀錄有異議者，應更正之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
